import{_ as i,o as e,c as o,ag as s}from"./chunks/framework.DtEl18Xn.js";const a="/getbiji-docs-v3/images/DjkIb888joPRP7xjk4tcgCkKnLe.png",l="/getbiji-docs-v3/images/EtrrbDaNjo4Xzyxnt1JcL6lAn6f.png",p="/getbiji-docs-v3/images/EvmHbdv6zoijoZxT9BjcakwEnGg.png",r="/getbiji-docs-v3/images/NyhIbA8dCoGyvSxQSSkcGZ2Qn2f.png",n="/getbiji-docs-v3/images/Wxrsb4g3AowqcFxDI3JcZvhunjf.png",c="/getbiji-docs-v3/images/Oi4xbbviaod7G8xMzHWcKPnqneR.png",g="/getbiji-docs-v3/images/Iuo8bqwbvoXHt3xrZUHc9GzVnKe.png",A=JSON.parse('{"title":"笔记发芽","description":"","frontmatter":{"title":"笔记发芽","category":"GetSeed AI录音卡","lastUpdated":"2026-03-14T15:00:05.650Z"},"headers":[],"relativePath":"getseed-ai录音卡/笔记发芽.md","filePath":"getseed-ai录音卡/笔记发芽.md"}'),_={name:"getseed-ai录音卡/笔记发芽.md"};function d(m,t,u,b,h,q){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="笔记发芽" tabindex="-1">笔记发芽 <a class="header-anchor" href="#笔记发芽" aria-label="Permalink to &quot;笔记发芽&quot;">​</a></h1><p>**笔记发芽——让每一条记录长出新的认知 **</p><p>**不只是帮你记住，更能帮你&quot;想到&quot; **</p><p>你每天说的话、开的会、读的书、冒出来的想法，都是种子。</p><p>大多数录音产品只负责把种子存起来——录音、转写、存档，笔记越存越多，最后变成信息的坟墓。GetSeed 要做的，是让这些种子发芽。AI 会理解你记录内容的思想内核，跨越领域和时空，帮你找到意想不到的关联，从记录里长出全新的认知。</p><p>**什么是&quot;发芽&quot;？ **</p><p>假设你用 GetSeed 记录了曾国藩的一句话「既往不恋，当下不杂，未来不迎」。普通的关键词搜索，输入&quot;曾国藩&quot;只会给你更多曾国藩——生平、语录、相关书籍，这是检索和罗列。</p><p>但「发芽」不同。AI 会理解这句话的思想内核是&quot;活在当下&quot;，然后告诉你：爱因斯坦说过「我从不去想未来，因为它来得已经够快了」，《功夫熊猫》里乌龟大师也说过「昨天是历史，明天是谜题，但今天是上帝的礼物」。这是理解和连接。你种下一颗种子，它能结出什么果子，就像开盲盒一样充满惊喜。</p><p><strong>适用场景</strong></p><ul><li>金句收藏：记录一句触动你的话，发芽报告帮你找到古今中外不同领域的共鸣表达，一句话变成一个思想图谱</li><li>读书听课：录下几句听书感想或课堂心得，AI 从你没想到的角度给出跨学科的关联知识，拓宽认知边界</li><li>灵感发散：记录一个初步想法，发芽报告帮你从不同维度延展思考，激发更多创意可能</li><li>会议复盘：录完一场讨论，对关键议题发芽，发现其他行业或历史中的类似案例和解决思路</li><li>日常感悟：随口记录生活中的一点感触，AI 帮你发现背后更深层的规律和连接</li></ul><p><strong>核心功能</strong></p><ul><li>发芽报告：AI 深度理解你的记录内容，跨领域、跨学科生成一份关联报告，呈现你没想到的角度和连接</li><li>每日种子：每天拥有 5 颗种子（即 5 次发芽机会），每天 0 点重置，不累计</li><li>整体发芽：基于录音卡中的新录音笔记，一键生成发芽报告，综合多条记录发现深层关联</li><li>单条发芽：也可以针对某一条特别有启发的笔记单独发芽，获得更聚焦的关联报告</li></ul><h1 id="app端-使用说明" tabindex="-1">APP端-使用说明 <a class="header-anchor" href="#app端-使用说明" aria-label="Permalink to &quot;APP端-使用说明&quot;">​</a></h1><ol><li>进入 Get笔记 APP，首页点击「GetSeed 录音卡」进入录音卡详情页</li><li>录音卡详情页顶部会展示发芽区域，点击「发芽」按钮，可以生成发芽报告</li><li>每天有 <strong>5</strong> 颗种子，可以用于生成发芽报告，生成一次消耗 <strong>1</strong> 颗，每天 0 点重置且不累计</li><li>每次发芽前，需要有 **新的录音笔记 **记录</li><li>发芽过程预计要 3-5 分钟，可以不必等待，发芽完会有 push 通知</li><li>点击右上角「发芽报告」，进入报告列表页查看报告详情</li><li>每条录音卡笔记，也可以单独发芽，笔记的...更多操作里，点击「笔记发芽」可以针对单条笔记来生成发芽报告，每次发芽也是消耗1颗种子</li><li>生成好的发芽报告，都在上面的「发芽报告」入口中来查看 <img src="'+a+'" alt=""></li></ol><p><img src="'+l+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+r+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+g+'" alt=""></p>',20)])])}const P=i(_,[["render",d]]);export{A as __pageData,P as default};
